void flip(std::vector<int>& arr, int i) {
    std::reverse(arr.begin(), arr.begin() + i + 1);
}

void pancakeSort(std::vector<int>& arr) {
    int n = arr.size();
    for (int curr_size = n; curr_size > 1; --curr_size) {
        auto max_it = std::max_element(arr.begin(), arr.begin() + curr_size);
        int max_idx = std::distance(arr.begin(), max_it);
        if (max_idx != curr_size - 1) {
            flip(arr, max_idx);
            flip(arr, curr_size - 1);
        }
    }
}

