int exponentialSearch(const std::vector<int>& arr, int x) {
    int n = arr.size();
    if (n == 0) return -1;
    if (arr[0] == x) return 0;
    int i = 1;
    while (i < n && arr[i] <= x) i = i * 2;
    return std::binary_search(arr.begin() + i/2, arr.begin() + std::min(i, n), x);
}

#include <vector>

int ternarySearch(const std::vector<int>& arr, int l, int r, int key) {
    if (r >= l) {
        int mid1 = l + (r - l) / 3;
        int mid2 = r - (r - l) / 3;
        if (arr[mid1] == key) return mid1;
        if (arr[mid2] == key) return mid2;
        if (key < arr[mid1]) return ternarySearch(arr, l, mid1 - 1, key);
        else if (key > arr[mid2]) return ternarySearch(arr, mid2 + 1, r, key);
        else return ternarySearch(arr, mid1 + 1, mid2 - 1, key);
    }
    return -1;
}

