using matrix = std::vector<std::vector<int>>;

matrix multiply(const matrix& A, const matrix& B) {
    int rA = A.size(), cA = A[0].size(), cB = B[0].size();
    matrix C(rA, std::vector<int>(cB, 0));
    for (int i = 0; i < rA; ++i) {
        for (int j = 0; j < cB; ++j) {
            for (int k = 0; k < cA; ++k) {
                C[i][j] += A[i][k] * B[k][j];
            }
        }
    }
    return C;
}

unsigned long long catalanDP(unsigned int n) {
    std::vector<unsigned long long> catalan(n + 1);
    catalan[0] = catalan[1] = 1;
    for (int i = 2; i <= n; i++) {
        catalan[i] = 0;
        for (int j = 0; j < i; j++)
            catalan[i] += catalan[j] * catalan[i - j - 1];
    }
    return catalan[n];
}

int phi(int n) {
    int result = n;
    for (int i = 2; i * i <= n; i++) {
        if (n % i == 0) {
            while (n % i == 0) n /= i;
            result -= result / i;
        }
    }
    if (n > 1) result -= result / n;
    return result;
}

int extendedGcd(int a, int b, int &x, int &y) {
    if (a == 0) {
        x = 0; y = 1;
        return b;
    }
    int x1, y1;
    int gcd = extendedGcd(b % a, a, x1, y1);
    x = y1 - (b / a) * x1;
    y = x1;
    return gcd;
}

long long gcd(long long a, long long b) { /* from above */ return b == 0 ? a : gcd(b, a % b); }

long long lcm(long long a, long long b) {
    if (a == 0 || b == 0) return 0;
    return std::abs(a * b) / gcd(a, b);
}

long long floorSqrt(long long x) {
    if (x == 0 || x == 1) return x;
    long long start = 1, end = x, ans = 0;
    while (start <= end) {
        long long mid = (start + end) / 2;
        if (mid * mid == x) return mid;
        if (mid <= x / mid) {
            start = mid + 1;
            ans = mid;
        } else {
            end = mid - 1;
        }
    }
    return ans;
}

