void rabinKarpSearch(const std::string& text, const std::string& pattern) {
    int d = 256, q = 101; // A prime number
    int m = pattern.length(), n = text.length();
    int p = 0, t = 0, h = 1;
    for (int i = 0; i < m - 1; i++) h = (h * d) % q;
    for (int i = 0; i < m; i++) {
        p = (d * p + pattern[i]) % q;
        t = (d * t + text[i]) % q;
    }
    for (int i = 0; i <= n - m; i++) {
        if (p == t && text.substr(i, m) == pattern) { /* Pattern found */ }
        if (i < n - m) {
            t = (d * (t - text[i] * h) + text[i + m]) % q;
            if (t < 0) t = (t + q);
        }
    }
}

