void backtrackPermute(std::vector<int>& nums, int start, std::vector<std::vector<int>>& result) {
    if (start == nums.size()) {
        result.push_back(nums);
        return;
    }
    for (int i = start; i < nums.size(); i++) {
        std::swap(nums[start], nums[i]);
        backtrackPermute(nums, start + 1, result);
        std::swap(nums[start], nums[i]); // backtrack
    }
}

