bool solveMazeUtil(const std::vector<std::vector<int>>& maze, int x, int y, std::vector<std::vector<int>>& sol) {
    int N = maze.size();
    if (x == N - 1 && y == N - 1 && maze[x][y] == 1) {
        sol[x][y] = 1;
        return true;
    }
    if (x >= 0 && x < N && y >= 0 && y < N && maze[x][y] == 1) {
        if (sol[x][y] == 1) return false; 
        sol[x][y] = 1;
        if (solveMazeUtil(maze, x + 1, y, sol) || solveMazeUtil(maze, x, y + 1, sol)) return true;
        sol[x][y] = 0; // backtrack
        return false;
    }
    return false;
}

