void permuteUniqueBacktrack(std::vector<int>& nums, int start, std::vector<std::vector<int>>& result) {
    if (start == nums.size()) {
        result.push_back(nums);
        return;
    }
    std::unordered_set<int> seen;
    for (int i = start; i < nums.size(); ++i) {
        if (seen.count(nums[i])) continue;
        seen.insert(nums[i]);
        std::swap(nums[start], nums[i]);
        permuteUniqueBacktrack(nums, start + 1, result);
        std::swap(nums[start], nums[i]); // backtrack
    }
}

#include <vector>

bool solveKnightTourUtil(int x, int y, int movei, int n, std::vector<std::vector<int>>& sol, const int xMove[], const int yMove[]) {
    if (movei == n * n) return true;
    for (int k = 0; k < 8; k++) {
        int next_x = x + xMove[k], next_y = y + yMove[k];
        if (next_x>=0 && next_x<n && next_y>=0 && next_y<n && sol[next_x][next_y]==-1) {
            sol[next_x][next_y] = movei;
            if (solveKnightTourUtil(next_x, next_y, movei + 1, n, sol, xMove, yMove)) return true;
            sol[next_x][next_y] = -1; // backtrack
        }
    }
    return false;
}

