bool graphColoringUtil(int v, int m, int n, const std::vector<std::vector<bool>>& graph, std::vector<int>& color) {
    if (v == n) return true;
    for (int c = 1; c <= m; c++) {
        if (isSafeToColor(v, c, n, graph, color)) {
            color[v] = c;
            if (graphColoringUtil(v + 1, m, n, graph, color)) return true;
            color[v] = 0; // backtrack
        }
    }
    return false;
}

#include <vector>

void calculate(int n, int pos, std::vector<bool>& visited, int& count) {
    if (pos > n) {
        count++;
        return;
    }
    for (int i = 1; i <= n; i++) {
        if (!visited[i] && (pos % i == 0 || i % pos == 0)) {
            visited[i] = true;
            calculate(n, pos + 1, visited, count);
            visited[i] = false; // backtrack
        }
    }
}

int countArrangement(int n) {
    int count = 0;
    std::vector<bool> visited(n + 1, false);
    calculate(n, 1, visited, count);
    return count;
}

