#include <unordered_map>

class LRUCache {
    int capacity_;
    std::list<std::pair<int, int>> items_;
    std::unordered_map<int, std::list<std::pair<int, int>>::iterator> cache_;
public:
    LRUCache(int capacity) : capacity_(capacity) {}
    int get(int key) {
        if (cache_.find(key) == cache_.end()) return -1;
        items_.splice(items_.begin(), items_, cache_[key]);
        return cache_[key]->second;
    }
    void put(int key, int value) {
        if (cache_.find(key) != cache_.end()) {
            items_.splice(items_.begin(), items_, cache_[key]);
            cache_[key]->second = value;
            return;
        }
        if (cache_.size() == capacity_) {
            int del_key = items_.back().first;
            items_.pop_back();
            cache_.erase(del_key);
        }
        items_.emplace_front(key, value);
        cache_[key] = items_.begin();
    }
};

