#include <vector>
#include <random>

std::vector<int> reservoirSampling(const std::vector<int>& stream, int k) {
    std::vector<int> reservoir(k);
    for (int i = 0; i < k; i++) reservoir[i] = stream[i];
    std::random_device rd;
    std::mt19937 gen(rd());
    for (int i = k; i < stream.size(); i++) {
        std::uniform_int_distribution<> distrib(0, i);
        int j = distrib(gen);
        if (j < k) reservoir[j] = stream[i];
    }
    return reservoir;
}

