void topologicalSortUtil(int v, const std::vector<std::vector<int>>& adj, std::vector<bool>& visited, std::stack<int>& st) {
    visited[v] = true;
    for (int i : adj[v]) {
        if (!visited[i]) topologicalSortUtil(i, adj, visited, st);
    }
    st.push(v);
}

std::vector<int> topologicalSort(int V, const std::vector<std::vector<int>>& adj) {
    std::stack<int> st;
    std::vector<bool> visited(V, false);
    for (int i = 0; i < V; i++) {
        if (!visited[i]) topologicalSortUtil(i, adj, visited, st);
    }
    std::vector<int> result;
    while(!st.empty()) { result.push_back(st.top()); st.pop(); }
    return result;
}

struct ListNode { int val; ListNode *next; };

bool hasCycle(ListNode *head) {
    if (!head || !head->next) return false;
    ListNode *slow = head, *fast = head->next;
    while (slow != fast) {
        if (!fast || !fast->next) return false;
        slow = slow->next;
        fast = fast->next->next;
    }
    return true;
}

bool knows(int a, int b); // Provided API

int findCelebrity(int n) {
    int candidate = 0;
    for (int i = 1; i < n; i++) {
        if (knows(candidate, i)) candidate = i;
    }
    for (int i = 0; i < n; i++) {
        if (i != candidate && (knows(candidate, i) || !knows(i, candidate))) return -1;
    }
    return candidate;
}

#include <vector>
#include <queue>

std::vector<std::vector<int>> floodFill(std::vector<std::vector<int>>& image, int sr, int sc, int newColor) {
    int oldColor = image[sr][sc];
    if (oldColor == newColor) return image;
    int R = image.size(), C = image[0].size();
    std::queue<std::pair<int, int>> q;
    q.push({sr, sc});
    image[sr][sc] = newColor;
    int dr[] = {0, 0, 1, -1};
    int dc[] = {1, -1, 0, 0};
    while(!q.empty()) {
        auto [r, c] = q.front(); q.pop();
        for(int i=0; i<4; ++i) {
            int nr = r + dr[i], nc = c + dc[i];
            if(nr>=0 && nr<R && nc>=0 && nc<C && image[nr][nc] == oldColor) {
                image[nr][nc] = newColor;
                q.push({nr, nc});
            }
        }
    }
    return image;
}

