int trap(const std::vector<int>& height) {
    if (height.empty()) return 0;
    int left = 0, right = height.size() - 1;
    int left_max = 0, right_max = 0, ans = 0;
    while (left < right) {
        if (height[left] < height[right]) {
            height[left] >= left_max ? (left_max = height[left]) : ans += (left_max - height[left]);
            ++left;
        } else {
            height[right] >= right_max ? (right_max = height[right]) : ans += (right_max - height[right]);
            --right;
        }
    }
    return ans;
}

public void BubbleSort(int[] arr)
{
    int n = arr.Length;
    bool swapped;
    for (int i = 0; i < n - 1; i++)
    {
        swapped = false;
        for (int j = 0; j < n - i - 1; j++)
        {
            if (arr[j] > arr[j + 1])
            {
                (arr[j], arr[j + 1]) = (arr[j + 1], arr[j]);
                swapped = true;
            }
        }
        if (!swapped) break;
    }
}

public void SelectionSort(int[] arr)
{
    int n = arr.Length;
    for (int i = 0; i < n - 1; i++)
    {
        int minIdx = i;
        for (int j = i + 1; j < n; j++)
        {
            if (arr[j] < arr[minIdx])
            {
                minIdx = j;
            }
        }
        if (minIdx != i)
        {
            (arr[minIdx], arr[i]) = (arr[i], arr[minIdx]);
        }
    }
}

public void InsertionSort(int[] arr)
{
    for (int i = 1; i < arr.Length; ++i)
    {
        int key = arr[i];
        int j = i - 1;
        while (j >= 0 && arr[j] > key)
        {
            arr[j + 1] = arr[j];
            j = j - 1;
        }
        arr[j + 1] = key;
    }
}

private void Merge(int[] arr, int l, int m, int r)
{
    int n1 = m - l + 1;
    int n2 = r - m;
    int[] L = new int[n1];
    int[] R = new int[n2];
    Array.Copy(arr, l, L, 0, n1);
    Array.Copy(arr, m + 1, R, 0, n2);
    int i = 0, j = 0, k = l;
    while (i < n1 && j < n2)
    {
        arr[k++] = (L[i] <= R[j]) ? L[i++] : R[j++];
    }
    while (i < n1) arr[k++] = L[i++];
    while (j < n2) arr[k++] = R[j++];
}

public void MergeSort(int[] arr, int l, int r)
{
    if (l >= r) return;
    int m = l + (r - l) / 2;
    MergeSort(arr, l, m);
    MergeSort(arr, m + 1, r);
    Merge(arr, l, m, r);
}

private int Partition(int[] arr, int low, int high)
{
    int pivot = arr[high];
    int i = (low - 1);
    for (int j = low; j <= high - 1; j++)
    {
        if (arr[j] < pivot)
        {
            i++;
            (arr[i], arr[j]) = (arr[j], arr[i]);
        }
    }
    (arr[i + 1], arr[high]) = (arr[high], arr[i + 1]);
    return (i + 1);
}

public void QuickSort(int[] arr, int low, int high)
{
    if (low < high)
    {
        int pi = Partition(arr, low, high);
        QuickSort(arr, low, pi - 1);
        QuickSort(arr, pi + 1, high);
    }
}

private void Heapify(int[] arr, int n, int i)
{
    int largest = i;
    int l = 2 * i + 1;
    int r = 2 * i + 2;
    if (l < n && arr[l] > arr[largest]) largest = l;
    if (r < n && arr[r] > arr[largest]) largest = r;
    if (largest != i)
    {
        (arr[i], arr[largest]) = (arr[largest], arr[i]);
        Heapify(arr, n, largest);
    }
}

public void HeapSort(int[] arr)
{
    int n = arr.Length;
    for (int i = n / 2 - 1; i >= 0; i--) Heapify(arr, n, i);
    for (int i = n - 1; i > 0; i--)
    {
        (arr[0], arr[i]) = (arr[i], arr[0]);
        Heapify(arr, i, 0);
    }
}

using System.Linq;

public void CountingSort(int[] arr)
{
    if (arr.Length == 0) return;
    int maxVal = arr.Max();
    int[] count = new int[maxVal + 1];
    foreach (int x in arr) count[x]++;
    int index = 0;
    for (int i = 0; i <= maxVal; i++)
    {
        while (count[i] > 0)
        {
            arr[index++] = i;
            count[i]--;
        }
    }
}

using System.Linq;

private void CountingSortForRadix(int[] arr, int exp)
{
    int n = arr.Length;
    int[] output = new int[n];
    int[] count = new int[10];
    for (int i = 0; i < n; i++) count[(arr[i] / exp) % 10]++;
    for (int i = 1; i < 10; i++) count[i] += count[i - 1];
    for (int i = n - 1; i >= 0; i--)
    {
        output[count[(arr[i] / exp) % 10] - 1] = arr[i];
        count[(arr[i] / exp) % 10]--;
    }
    Array.Copy(output, arr, n);
}

public void RadixSort(int[] arr)
{
    if (arr.Length == 0) return;
    int m = arr.Max();
    for (int exp = 1; m / exp > 0; exp *= 10)
    {
        CountingSortForRadix(arr, exp);
    }
}

using System.Collections.Generic;

public void BucketSort(float[] arr)
{
    int n = arr.Length;
    if (n <= 0) return;
    List<float>[] buckets = new List<float>[n];
    for (int i = 0; i < n; i++) buckets[i] = new List<float>();
    for (int i = 0; i < n; i++)
    {
        int bucketIndex = (int)(n * arr[i]);
        buckets[bucketIndex].Add(arr[i]);
    }
    for (int i = 0; i < n; i++) buckets[i].Sort();
    int index = 0;
    for (int i = 0; i < n; i++)
    {
        foreach (float item in buckets[i])
        {
            arr[index++] = item;
        }
    }
}

public void ShellSort(int[] arr)
{
    int n = arr.Length;
    for (int gap = n / 2; gap > 0; gap /= 2)
    {
        for (int i = gap; i < n; i += 1)
        {
            int temp = arr[i];
            int j;
            for (j = i; j >= gap && arr[j - gap] > temp; j -= gap)
            {
                arr[j] = arr[j - gap];
            }
            arr[j] = temp;
        }
    }
}

private int GetNextGap(int gap)
{
    gap = (gap * 10) / 13;
    return gap < 1 ? 1 : gap;
}

public void CombSort(int[] arr)
{
    int n = arr.Length;
    int gap = n;
    bool swapped = true;
    while (gap != 1 || swapped)
    {
        gap = GetNextGap(gap);
        swapped = false;
        for (int i = 0; i < n - gap; i++)
        {
            if (arr[i] > arr[i + gap])
            {
                (arr[i], arr[i + gap]) = (arr[i + gap], arr[i]);
                swapped = true;
            }
        }
    }
}

private void Flip(int[] arr, int k)
{
    Array.Reverse(arr, 0, k + 1);
}

public void PancakeSort(int[] arr)
{
    int n = arr.Length;
    for (int currSize = n; currSize > 1; --currSize)
    {
        int maxIndex = Array.IndexOf(arr, arr.Take(currSize).Max());
        if (maxIndex != currSize - 1)
        {
            if (maxIndex != 0) Flip(arr, maxIndex);
            Flip(arr, currSize - 1);
        }
    }
}

public void GnomeSort(int[] arr)
{
    int index = 0;
    while (index < arr.Length)
    {
        if (index == 0) index++;
        if (arr[index] >= arr[index - 1])
        {
            index++;
        } 
        else
        {
            (arr[index], arr[index - 1]) = (arr[index - 1], arr[index]);
            index--;
        }
    }
}

public void CocktailShakerSort(int[] arr)
{
    bool swapped = true;
    int start = 0;
    int end = arr.Length - 1;
    while (swapped)
    {
        swapped = false;
        for (int i = start; i < end; ++i)
        {
            if (arr[i] > arr[i + 1])
            {
                (arr[i], arr[i + 1]) = (arr[i + 1], arr[i]);
                swapped = true;
            }
        }
        if (!swapped) break;
        swapped = false;
        --end;
        for (int i = end - 1; i >= start; --i)
        {
            if (arr[i] > arr[i + 1])
            {
                (arr[i], arr[i + 1]) = (arr[i + 1], arr[i]);
                swapped = true;
            }
        }
        ++start;
    }
}

