    var primeNumbers = new List<int>();
    for (int p = 2; p <= n; p++) if (prime[p]) primeNumbers.Add(p);
    return primeNumbers;
}

public long Power(long baseVal, long exp, long mod)
{
    long res = 1;
    baseVal %= mod;
    while (exp > 0)
    {
        if (exp % 2 == 1) res = (res * baseVal) % mod;
        exp >>= 1;
        baseVal = (baseVal * baseVal) % mod;
    }
    return res;
}

public long NCr(int n, int r)
{
    if (r < 0 || r > n) return 0;
    if (r == 0 || r == n) return 1;
    if (r > n / 2) r = n - r;
    long res = 1;
    for (int i = 1; i <= r; i++)
    {
        res = res * (n - i + 1) / i;
    }
    return res;
}

public long NPr(int n, int r)
