public bool IsPalindromeNumber(int n)
{
    if (n < 0 || (n % 10 == 0 && n != 0)) return false;
    int reversedHalf = 0;
    while (n > reversedHalf)
    {
        reversedHalf = reversedHalf * 10 + n % 10;
        n /= 10;
    }
    return n == reversedHalf || n == reversedHalf / 10;
}

public int[,] MultiplyMatrices(int[,] A, int[,] B)
{
    int rA = A.GetLength(0), cA = A.GetLength(1);
    int rB = B.GetLength(0), cB = B.GetLength(1);
    if (cA != rB) throw new ArgumentException("Matrices cannot be multiplied.");
    int[,] C = new int[rA, cB];
    for (int i = 0; i < rA; i++)
        for (int j = 0; j < cB; j++)
            for (int k = 0; k < cA; k++)
                C[i, j] += A[i, k] * B[k, j];
    return C;
}

