private BigInteger BinomialCoefficient(int n, int k)
{
    if (k < 0 || k > n) return 0;
    if (k == 0 || k == n) return 1;
    if (k > n / 2) k = n - k;
    BigInteger res = 1;
    for (int i = 1; i <= k; i++) res = res * (n - i + 1) / i;
    return res;
}

public int Phi(int n)
{
