public long FloorSqrt(long x)
{
    if (x < 0) throw new ArgumentException("Input must be non-negative");
    if (x == 0 || x == 1) return x;
    long start = 1, end = x, ans = 0;
    while (start <= end)
    {
        long mid = start + (end - start) / 2;
        if (mid > x / mid) { // to avoid overflow
            end = mid - 1;
        } else {
            ans = mid;
            start = mid + 1;
        }
    }
    return ans;
}

