using System;

public int Knapsack(int W, int[] wt, int[] val)
{
    int n = val.Length;
    int[,] dp = new int[n + 1, W + 1];
    for (int i = 1; i <= n; i++)
    {
        for (int w = 1; w <= W; w++)
        {
            if (wt[i - 1] <= w)
            {
                dp[i, w] = Math.Max(val[i - 1] + dp[i - 1, w - wt[i - 1]], dp[i - 1, w]);
            } 
            else 
            {
                dp[i, w] = dp[i - 1, w];
            }
        }
    }
    return dp[n, W];
}

