    int[] val = new int[n + 1];
    val[0] = 0;
    for (int i = 1; i <= n; i++)
    {
        int maxVal = int.MinValue;
        for (int j = 0; j < i; j++)
        {
            maxVal = Math.Max(maxVal, prices[j] + val[i - j - 1]);
        }
        val[i] = maxVal;
    }
    return val[n];
}

