public bool SolveSudoku(char[][] board)
{
    for (int i = 0; i < 9; i++)
    {
        for (int j = 0; j < 9; j++)
        {
            if (board[i][j] == '.')
            {
                for (char c = '1'; c <= '9'; c++)
                {
                    if (IsValid(board, i, j, c))
                    {
                        board[i][j] = c;
                        if (SolveSudoku(board)) return true;
                        else board[i][j] = '.'; // backtrack
                    }
                }
                return false;
            }
        }
    }
    return true;
}

