private void BacktrackCombinationSum(int[] candidates, int target, int start, List<int> current, IList<IList<int>> result)
{
    if (target == 0) { result.Add(new List<int>(current)); return; }
    for (int i = start; i < candidates.Length && target >= candidates[i]; i++)
    {
        current.Add(candidates[i]);
        BacktrackCombinationSum(candidates, target - candidates[i], i, current, result);
        current.RemoveAt(current.Count - 1); // backtrack
    }
}

private bool Search(char[][] board, string word, int i, int j, int index)
{
    if (index == word.Length) return true;
    if (i < 0 || i >= board.Length || j < 0 || j >= board[0].Length || board[i][j] != word[index]) return false;
    char temp = board[i][j];
    board[i][j] = ' ';
    bool found = Search(board, word, i + 1, j, index + 1) || Search(board, word, i - 1, j, index + 1) ||
                 Search(board, word, i, j + 1, index + 1) || Search(board, word, i, j - 1, index + 1);
    board[i][j] = temp; // backtrack
    return found;
}

