private readonly string[] mapping = { "0", "1", "abc", "def", "ghi", "jkl", "mno", "pqrs", "tuv", "wxyz" };

private void BacktrackPhone(string digits, int index, System.Text.StringBuilder current, IList<string> result)
{
    if (index == digits.Length) { result.Add(current.ToString()); return; }
    string letters = mapping[digits[index] - '0'];
    foreach (char letter in letters)
    {
        current.Append(letter);
        BacktrackPhone(digits, index + 1, current, result);
        current.Length--; // backtrack
    }
}

