private void BacktrackPartition(string s, int start, List<string> current, IList<IList<string>> result)
{
    if (start == s.Length) { result.Add(new List<string>(current)); return; }
    for (int i = start; i < s.Length; i++)
    {
        if (IsPalindrome(s, start, i))
        {
            current.Add(s.Substring(start, i - start + 1));
            BacktrackPartition(s, i + 1, current, result);
            current.RemoveAt(current.Count - 1); // backtrack
        }
    }
}
