private void BacktrackPermuteUnique(int[] nums, bool[] used, List<int> current, IList<IList<int>> result)
{
    if (current.Count == nums.Length) { result.Add(new List<int>(current)); return; }
    for (int i = 0; i < nums.Length; i++)
    {
        if (used[i] || (i > 0 && nums[i] == nums[i - 1] && !used[i - 1])) continue;
        used[i] = true;
        current.Add(nums[i]);
        BacktrackPermuteUnique(nums, used, current, result);
        current.RemoveAt(current.Count - 1);
        used[i] = false;
    }
}

private int count = 0;

private void Calculate(int n, int pos, bool[] visited)
{
    if (pos > n) { count++; return; }
    for (int i = 1; i <= n; i++)
    {
        if (!visited[i] && (pos % i == 0 || i % pos == 0))
        {
            visited[i] = true;
            Calculate(n, pos + 1, visited);
            visited[i] = false; // backtrack
        }
    }
}

public int CountArrangement(int n)
{
    bool[] visited = new bool[n + 1];
    Calculate(n, 1, visited);
    return count;
}

