private void Restore(string s, int index, int dots, string current, IList<string> result)
{
    if (dots == 4 && index == s.Length) { result.Add(current.Substring(0, current.Length - 1)); return; }
    if (dots >= 4 || index >= s.Length) return;
    for (int len = 1; len <= 3 && index + len <= s.Length; len++)
    {
        string numStr = s.Substring(index, len);
        if (numStr.Length > 1 && numStr[0] == '0') continue;
        if (int.Parse(numStr) <= 255)
        {
            Restore(s, index + len, dots + 1, current + numStr + ".", result);
        }
    }
}

private bool IsSafe(int[][] maze, int x, int y, int n) { return x >= 0 && x < n && y >= 0 && y < n && maze[x][y] == 1; }

private bool SolveMazeUtil(int[][] maze, int x, int y, int[][] sol, int n)
{
    if (x == n - 1 && y == n - 1 && maze[x][y] == 1) { sol[x][y] = 1; return true; }
    if (IsSafe(maze, x, y, n))
    {
        if (sol[x][y] == 1) return false;
        sol[x][y] = 1;
        if (SolveMazeUtil(maze, x + 1, y, sol, n) || SolveMazeUtil(maze, x, y + 1, sol, n)) return true;
        sol[x][y] = 0; // backtrack
        return false;
    }
    return false;
}

