private bool GraphColoringUtil(bool[][] graph, int m, int[] color, int v, int n)
{
    if (v == n) return true;
    for (int c = 1; c <= m; c++)
    {
        if (IsSafeToColor(v, graph, color, c, n))
        {
            color[v] = c;
            if (GraphColoringUtil(graph, m, color, v + 1, n)) return true;
            color[v] = 0; // backtrack
        }
    }
    return false;
}

