public int[] ReservoirSampling(int[] stream, int k)
{
    int[] reservoir = new int[k];
    Array.Copy(stream, reservoir, k);
    Random rand = new Random();
    for (int i = k; i < stream.Length; i++)
    {
        int j = rand.Next(i + 1);
        if (j < k) reservoir[j] = stream[i];
    }
    return reservoir;
}

