public void bucketSort(float[] arr) {
    int n = arr.length;
    if (n <= 0) return;
    @SuppressWarnings("unchecked")
    List<Float>[] buckets = new LinkedList[n];
    for (int i = 0; i < n; i++) buckets[i] = new LinkedList<>();
    for (int i = 0; i < n; i++) {
        int bucketIndex = (int) (n * arr[i]);
        buckets[bucketIndex].add(arr[i]);
    }
    for (int i = 0; i < n; i++) Collections.sort(buckets[i]);
    int index = 0;
    for (int i = 0; i < n; i++) {
        for (float item : buckets[i]) {
            arr[index++] = item;
        }
    }
}

public void shellSort(int[] arr) {
    int n = arr.length;
    for (int gap = n / 2; gap > 0; gap /= 2) {
        for (int i = gap; i < n; i++) {
            int temp = arr[i];
            int j;
            for (j = i; j >= gap && arr[j - gap] > temp; j -= gap) {
                arr[j] = arr[j - gap];
            }
            arr[j] = temp;
        }
    }
}

private int getNextGap(int gap) {
    gap = (gap * 10) / 13;
    return Math.max(gap, 1);
}

public void combSort(int[] arr) {
    int n = arr.length;
    int gap = n;
    boolean swapped = true;
    while (gap != 1 || swapped) {
        gap = getNextGap(gap);
        swapped = false;
        for (int i = 0; i < n - gap; i++) {
            if (arr[i] > arr[i + gap]) {
                int temp = arr[i];
                arr[i] = arr[i + gap];
                arr[i + gap] = temp;
                swapped = true;
            }
        }
    }
}

private void flip(int[] arr, int k) {
    for (int i = 0; i < (k + 1) / 2; i++) {
        int temp = arr[i];
        arr[i] = arr[k - i];
        arr[k - i] = temp;
    }
}

public void pancakeSort(int[] arr) {
    int n = arr.length;
    for (int currSize = n; currSize > 1; --currSize) {
        int maxIndex = 0;
        for (int i = 1; i < currSize; i++) {
            if (arr[i] > arr[maxIndex]) {
                maxIndex = i;
            }
        }
        if (maxIndex != currSize - 1) {
            flip(arr, maxIndex);
            flip(arr, currSize - 1);
        }
    }
}

public void gnomeSort(int[] arr) {
    int index = 0;
    while (index < arr.length) {
        if (index == 0) {
            index++;
        }
        if (arr[index] >= arr[index - 1]) {
            index++;
        } else {
            int temp = arr[index];
            arr[index] = arr[index - 1];
            arr[index - 1] = temp;
            index--;
        }
    }
}

public void cocktailShakerSort(int[] arr) {
    boolean swapped = true;
    int start = 0;
    int end = arr.length - 1;
    while (swapped) {
        swapped = false;
        for (int i = start; i < end; ++i) {
            if (arr[i] > arr[i + 1]) {
                int temp = arr[i]; arr[i] = arr[i+1]; arr[i+1] = temp;
                swapped = true;
            }
        }
        if (!swapped) break;
        swapped = false;
        --end;
        for (int i = end - 1; i >= start; --i) {
            if (arr[i] > arr[i + 1]) {
                int temp = arr[i]; arr[i] = arr[i+1]; arr[i+1] = temp;
                swapped = true;
            }
        }
        ++start;
    }
}

