public void bfs(int startNode, int V, List<Integer>[] adj) {
    boolean[] visited = new boolean[V];
    Queue<Integer> queue = new LinkedList<>();
    visited[startNode] = true;
    queue.add(startNode);
    while (!queue.isEmpty()) {
        int v = queue.poll();
        // Process node v
        for (int neighbor : adj[v]) {
            if (!visited[neighbor]) {
                visited[neighbor] = true;
                queue.add(neighbor);
            }
        }
    }
}

