public int exponentialSearch(int[] arr, int x) {
    int n = arr.length;
    if (n > 0 && arr[0] == x) return 0;
    int i = 1;
    while (i < n && arr[i] <= x) i *= 2;
    return Arrays.binarySearch(arr, i / 2, Math.min(i, n), x);
}

public int ternarySearch(int[] arr, int l, int r, int key) {
    if (r >= l) {
        int mid1 = l + (r - l) / 3;
        int mid2 = r - (r - l) / 3;
        if (arr[mid1] == key) return mid1;
        if (arr[mid2] == key) return mid2;
        if (key < arr[mid1]) return ternarySearch(arr, l, mid1 - 1, key);
        else if (key > arr[mid2]) return ternarySearch(arr, mid2 + 1, r, key);
        else return ternarySearch(arr, mid1 + 1, mid2 - 1, key);
    }
    return -1;
}

public int findMin(int[] nums) {
    int low = 0, high = nums.length - 1;
    while (low < high) {
        int mid = low + (high - low) / 2;
        if (nums[mid] > nums[high]) {
            low = mid + 1;
        } else {
            high = mid;
        }
    }
    return nums[low];
}

public int searchRotated(int[] nums, int target) {
    int low = 0, high = nums.length - 1;
    while (low <= high) {
        int mid = low + (high - low) / 2;
        if (nums[mid] == target) return mid;
        if (nums[low] <= nums[mid]) {
            if (target >= nums[low] && target < nums[mid]) high = mid - 1;
            else low = mid + 1;
        } else {
            if (target > nums[mid] && target <= nums[high]) low = mid + 1;
            else high = mid - 1;
        }
    }
    return -1;
}

private int findBound(int[] nums, int target, boolean isFirst) {
    int low = 0, high = nums.length - 1;
    int result = -1;
    while (low <= high) {
        int mid = low + (high - low) / 2;
        if (nums[mid] == target) {
            result = mid;
            if (isFirst) high = mid - 1;
            else low = mid + 1;
        } else if (nums[mid] < target) low = mid + 1;
        else high = mid - 1;
    }
    return result;
}

public int[] searchRange(int[] nums, int target) {
    int first = findBound(nums, target, true);
    int last = findBound(nums, target, false);
    return new int[] { first, last };
}

public int findPeakElement(int[] nums) {
    int left = 0, right = nums.length - 1;
    while (left < right) {
        int mid = left + (right - left) / 2;
        if (nums[mid] > nums[mid + 1]) {
            right = mid;
        } else {
            left = mid + 1;
        }
    }
    return left;
}

