    int[] val = new int[n + 1];
    val[0] = 0;
    for (int i = 1; i <= n; i++) {
        int maxVal = Integer.MIN_VALUE;
        for (int j = 0; j < i; j++) {
            maxVal = Math.max(maxVal, prices[j] + val[i - j - 1]);
        }
        val[i] = maxVal;
    }
    return val[n];
}

