public List<Integer> rabinKarpSearch(String text, String pattern) {
    final int d = 256, q = 101;
    int m = pattern.length(), n = text.length();
    int p = 0, t = 0, h = 1;
    List<Integer> result = new ArrayList<>();
    for (int i = 0; i < m - 1; i++) h = (h * d) % q;
    for (int i = 0; i < m; i++) { p = (d * p + pattern.charAt(i)) % q; t = (d * t + text.charAt(i)) % q; }
    for (int i = 0; i <= n - m; i++) {
        if (p == t && text.substring(i, i + m).equals(pattern)) result.add(i);
        if (i < n - m) { t = (d * (t - text.charAt(i) * h) + text.charAt(i + m)) % q; if (t < 0) t += q; }
    }
    return result;
}

