private void backtrackPermute(int[] nums, int start, List<List<Integer>> result) {
    if (start == nums.length) {
        result.add(new ArrayList<>(Arrays.asList(Arrays.stream(nums).boxed().toArray(Integer[]::new))));
        return;
    }
    for (int i = start; i < nums.length; i++) {
        int temp = nums[start]; nums[start] = nums[i]; nums[i] = temp;
        backtrackPermute(nums, start + 1, result);
        temp = nums[start]; nums[start] = nums[i]; nums[i] = temp; // backtrack
    }
}

