private void backtrackPermuteUnique(int[] nums, boolean[] used, List<Integer> current, List<List<Integer>> result) {
    if (current.size() == nums.length) { result.add(new ArrayList<>(current)); return; }
    for (int i = 0; i < nums.length; i++) {
        if (used[i] || (i > 0 && nums[i] == nums[i - 1] && !used[i - 1])) continue;
        used[i] = true;
        current.add(nums[i]);
        backtrackPermuteUnique(nums, used, current, result);
        current.remove(current.size() - 1);
        used[i] = false;
    }
}

private int count = 0;

private void calculate(int n, int pos, boolean[] visited) {
    if (pos > n) { count++; return; }
    for (int i = 1; i <= n; i++) {
        if (!visited[i] && (pos % i == 0 || i % pos == 0)) {
            visited[i] = true;
            calculate(n, pos + 1, visited);
            visited[i] = false; // backtrack
        }
    }
}

