private void restore(String s, int index, int dots, String current, List<String> result) {
    if (dots == 4 && index == s.length()) { result.add(current.substring(0, current.length() - 1)); return; }
    if (dots >= 4 || index >= s.length()) return;
    for (int len = 1; len <= 3 && index + len <= s.length(); len++) {
        String numStr = s.substring(index, index + len);
        if (numStr.length() > 1 && numStr.startsWith("0")) continue;
        if (Integer.parseInt(numStr) <= 255) {
            restore(s, index + len, dots + 1, current + numStr + ".", result);
        }
    }
}

private boolean isSafe(int[][] maze, int x, int y, int n) { return x >= 0 && x < n && y >= 0 && y < n && maze[x][y] == 1; }

private boolean solveMazeUtil(int[][] maze, int x, int y, int[][] sol, int n) {
    if (x == n - 1 && y == n - 1 && maze[x][y] == 1) { sol[x][y] = 1; return true; }
    if (isSafe(maze, x, y, n)) {
        if (sol[x][y] == 1) return false;
        sol[x][y] = 1;
        if (solveMazeUtil(maze, x + 1, y, sol, n) || solveMazeUtil(maze, x, y + 1, sol, n)) return true;
        sol[x][y] = 0; // backtrack
        return false;
    }
    return false;
}

