    for (int c = 1; c <= m; c++) {
        if (isSafeToColor(v, graph, color, c, n)) {
            color[v] = c;
            if (graphColoringUtil(graph, m, color, v + 1, n)) return true;
            color[v] = 0; // backtrack
        }
    }
    return false;
}

private int dfs(int[][] grid, int r, int c) {
    if (r < 0 || r >= grid.length || c < 0 || c >= grid[0].length || grid[r][c] == 0) return 0;
    int gold = grid[r][c];
    grid[r][c] = 0; // Mark as visited
    int maxGold = 0;
    maxGold = Math.max(maxGold, dfs(grid, r + 1, c));
    maxGold = Math.max(maxGold, dfs(grid, r - 1, c));
    maxGold = Math.max(maxGold, dfs(grid, r, c + 1));
    maxGold = Math.max(maxGold, dfs(grid, r, c - 1));
    grid[r][c] = gold; // backtrack
    return gold + maxGold;
}

