public void sortColors(int[] nums) {
    int low = 0, mid = 0, high = nums.length - 1;
    while (mid <= high) {
        if (nums[mid] == 0) {
            int temp = nums[low]; nums[low++] = nums[mid]; nums[mid++] = temp;
        } else if (nums[mid] == 1) {
            mid++;
        } else {
            int temp = nums[mid]; nums[mid] = nums[high]; nums[high--] = temp;
        }
    }
}

public int josephus(int n, int k) {
    if (n == 1) return 0;
    return (josephus(n - 1, k) + k) % n;
}

import java.util.Random;

public int[] reservoirSampling(int[] stream, int k) {
    int[] reservoir = new int[k];
    System.arraycopy(stream, 0, reservoir, 0, k);
    Random rand = new Random();
    for (int i = k; i < stream.length; i++) {
        int j = rand.nextInt(i + 1);
        if (j < k) reservoir[j] = stream[i];
    }
    return reservoir;
}

public int majorityElement(int[] nums) {
    int count = 0;
    Integer candidate = null;
    for (int num : nums) {
        if (count == 0) candidate = num;
        count += (num == candidate) ? 1 : -1;
    }
    return candidate;
}

import java.util.*;

private void topologicalSortUtil(int v, List<Integer>[] adj, boolean[] visited, Stack<Integer> stack) {
    visited[v] = true;
    for (int i : adj[v])
        if (!visited[i]) topologicalSortUtil(i, adj, visited, stack);
    stack.push(v);
}

public int[] topologicalSort(int V, List<Integer>[] adj) {
    Stack<Integer> stack = new Stack<>();
    boolean[] visited = new boolean[V];
    for (int i = 0; i < V; i++)
        if (!visited[i]) topologicalSortUtil(i, adj, visited, stack);
    int[] result = new int[V];
    int i=0;
    while(!stack.isEmpty()) result[i++] = stack.pop();
    return result;
}

class ListNode { int val; ListNode next; }

public boolean hasCycle(ListNode head) {
    ListNode slow = head, fast = head;
    while (fast != null && fast.next != null) {
        slow = slow.next;
        fast = fast.next.next;
        if (slow == fast) return true;
    }
    return false;
}

import java.util.LinkedList;
import java.util.Queue;

public int[][] floodFill(int[][] image, int sr, int sc, int newColor) {
    int oldColor = image[sr][sc];
    if (oldColor == newColor) return image;
    int R = image.length, C = image[0].length;
    Queue<int[]> queue = new LinkedList<>();
    queue.add(new int[]{sr, sc});
    image[sr][sc] = newColor;
    int[] dr = {0, 0, 1, -1}, dc = {1, -1, 0, 0};
    while (!queue.isEmpty()) {
        int[] cell = queue.poll();
        for (int i = 0; i < 4; i++) {
            int nr = cell[0] + dr[i], nc = cell[1] + dc[i];
            if (nr >= 0 && nr < R && nc >= 0 && nc < C && image[nr][nc] == oldColor) {
                image[nr][nc] = newColor;
                queue.add(new int[]{nr, nc});
            }
        }
    }
    return image;
}

public int trap(int[] height) {
    if (height.length == 0) return 0;
    int left = 0, right = height.length - 1;
    int leftMax = 0, rightMax = 0, ans = 0;
    while (left < right) {
        if (height[left] < height[right]) {
            if (height[left] >= leftMax) leftMax = height[left];
            else ans += leftMax - height[left];
            left++;
        } else {
            if (height[right] >= rightMax) rightMax = height[right];
            else ans += rightMax - height[right];
            right--;
        }
    }
    return ans;
}

/* The knows API is defined in the parent class Relation.
      boolean knows(int a, int b); */

public class Solution extends Relation {
    public int findCelebrity(int n) {
        int candidate = 0;
        for (int i = 1; i < n; i++) {
            if (knows(candidate, i)) {
                candidate = i;
            }
        }
        for (int i = 0; i < n; i++) {
            if (i != candidate && (knows(candidate, i) || !knows(i, candidate))) {
                return -1;
            }
        }
        return candidate;
    }
}
